1312	fn rbtdrf_rv_rbrv_all_vessels(dir: &Path) -> rbtdre_Verdict {
1313	    let root = match std::env::current_dir() {
1314	        Ok(r) => r,
1315	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1316	    };
1317	
1318	    // Discover vessels: source rbrr.env to get RBRR_VESSEL_DIR, scan it
1319	    let buv = root.join(RBTDRF_BUV_VALIDATION);
1320	    let rbk = root.join(RBTDRF_RBK_ROOT);
1321	    let buv_p = rbtdrx_native_to_posix(&buv);
1322	    let rbk_p = rbtdrx_native_to_posix(&rbk);
1323	    let script = format!(
1324	        "set -euo pipefail\n\
1325	         source '{}'\n\
1326	         source '{}/rbcc_Constants.sh'\n\
1327	         source '{}/rbgc_Constants.sh'\n\
1328	         source '{}/rbrr_regime.sh'\n\
1329	         source '{}/rbrd_regime.sh'\n\
1330	         source '{}/rbdc_DerivedConstants.sh'\n\
1331	         zbuv_kindle\nzrbcc_kindle\n\
1332	         source \"${{PWD}}/{moorings}/rbrr.env\"\n\
1333	         source \"${{PWD}}/{moorings}/rbrd.env\"\n\
1334	         zrbrr_kindle\nzrbrd_kindle\nzrbrr_enforce\nzrbrd_enforce\nzrbdc_kindle\n\
1335	         echo \"${{RBRR_VESSEL_DIR}}\"",
1336	        buv_p,
1337	        rbk_p, rbk_p, rbk_p, rbk_p, rbk_p,
1338	        moorings = crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR,
1339	    );
1340	
1341	    let vessel_dir = match rbtdrf_run_bash(&root, &script, dir, "rbrv-discover") {
1342	        Ok((0, stdout, _)) => stdout.trim().to_string(),
1343	        Ok((code, _, _)) => {
1344	            return rbtdre_Verdict::Fail(format!("vessel discovery failed (exit {})", code));
1345	        }
1346	        Err(e) => return rbtdre_Verdict::Fail(e),
1347	    };
1348	
1349	    let entries = match std::fs::read_dir(&vessel_dir) {
1350	        Ok(e) => e,
1351	        Err(e) => {
1352	            return rbtdre_Verdict::Fail(format!("cannot read {}: {}", vessel_dir, e));
1353	        }
1354	    };
1355	
1356	    let mut found = false;
1357	    for entry in entries.filter_map(|e| e.ok()) {
1358	        let path = entry.path();
1359	        if path.is_dir() && path.join("rbrv.env").exists() {
1360	            found = true;
1361	            let sigil = entry.file_name().to_string_lossy().to_string();
1362	            if let Err(e) = rbtdrf_run_tt(
1363	                &root, RBTDGC_VALIDATE_VESSEL, &[&sigil], dir,
1364	                &format!("rbrv-{}-validate", sigil),
1365	            ) {
1366	                return rbtdre_Verdict::Fail(e);
1367	            }
1368	        }
1369	    }
1370	
1371	    if !found {
1372	        return rbtdre_Verdict::Fail(format!("no vessels found in {}", vessel_dir));
1373	    }
1374	    rbtdre_Verdict::Pass
1375	}
