1671	    let tt = match rbtdri_find_tabtarget_global(&root, RBTDGC_UNMAKE_DEPOT) {
1672	        Ok(p) => p,
1673	        Err(e) => return rbtdre_Verdict::Fail(e),
1674	    };
1675	
1676	    let output = match rbtdri_tabtarget_command(&tt).current_dir(&root).output() {
1677	        Ok(o) => o,
