1819	            return rbtdre_Verdict::Fail(format!(
1820	                "resolve RBRR_VESSEL_DIR failed (exit {}): {}",
1821	                code, stderr
1822	            ));
1823	        }
1824	        Err(e) => return rbtdre_Verdict::Fail(e),
1825	    };
1826	    let vessel_dir = vessel_dir.trim();
1827	    if vessel_dir.is_empty() {
1828	        return rbtdre_Verdict::Fail("RBRR_VESSEL_DIR resolved to empty string".to_string());
1829	    }
1830	
1831	    let entries = match std::fs::read_dir(vessel_dir) {
1832	        Ok(e) => e,
1833	        Err(e) => {
1834	            return rbtdre_Verdict::Fail(format!(
1835	                "read_dir({}) failed: {}",
1836	                vessel_dir, e
1837	            ));
1838	        }
1839	    };
1840	
1841	    // rbw-fhv silently succeeds on non-conjure vessels (hygiene contract is
1842	    // vacuously satisfied where there's no local Dockerfile), so theurge
1843	    // iterates without pre-filtering — surface integrity stays intact and
1844	    // no rbrv.env internals are touched here.
1845	    let mut count: usize = 0;
1846	    for entry in entries {
1847	        let entry = match entry {
1848	            Ok(e) => e,
1849	            Err(e) => return rbtdre_Verdict::Fail(format!("dir entry error: {}", e)),
1850	        };
1851	        let path = entry.path();
1852	        if !path.is_dir() {
1853	            continue;
1854	        }
1855	        if !path.join("rbrv.env").is_file() {
1856	            continue;
1857	        }
1858	        let sigil = match path.file_name().and_then(|s| s.to_str()) {
1859	            Some(s) => s.to_string(),
1860	            None => continue,
1861	        };
1862	
1863	        if let Err(e) = rbtdrf_run_tt(
1864	            &root,
1865	            RBTDGC_HYGIENE_CHECK_VESSEL,
1866	            &[&sigil],
1867	            dir,
1868	            &format!("vessel-{}", sigil),
1869	        ) {
1870	            return rbtdre_Verdict::Fail(e);
1871	        }
1872	        count += 1;
1873	    }
1874	
1875	    if count == 0 {
1876	        return rbtdre_Verdict::Fail(format!(
1877	            "zero vessels iterated under {} — busted RBRR_VESSEL_DIR resolution",
1878	            vessel_dir
1879	        ));
1880	    }
1881	
1882	    rbtdre_Verdict::Pass
1883	}
