1894	fn rbtdrf_np_run(
1895	    dir: &Path,
1896	    label: &str,
1897	    ostype: &str,
1898	    input: &str,
1899	    expect: Option<&str>,
1900	) -> rbtdre_Verdict {
1901	    let root = match std::env::current_dir() {
1902	        Ok(r) => r,
1903	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1904	    };
1905	    let buc = root.join(RBTDRF_BUC_COMMAND);
1906	
1907	    let assertion = match expect {
1908	        Some(out) => format!("test \"$(buc_native_path_capture '{}')\" = '{}'", input, out),
1909	        None => format!("buc_native_path_capture '{}'", input),
1910	    };
1911	    let script = format!(
1912	        "set -euo pipefail\nsource '{}'\nexport BURD_OSTYPE='{}'\n{}",
1913	        rbtdrx_native_to_posix(&buc),
1914	        ostype,
1915	        assertion,
1916	    );
1917	
1918	    let expect_ok = expect.is_some();
1919	    match rbtdrf_run_bash(&root, &script, dir, label) {
1920	        Ok((code, _, _)) => {
1921	            let ok = code == 0;
1922	            if ok == expect_ok {
1923	                rbtdre_Verdict::Pass
1924	            } else if expect_ok {
1925	                rbtdre_Verdict::Fail(format!("{}: expected ok, got exit {}", label, code))
1926	            } else {
1927	                rbtdre_Verdict::Fail(format!("{}: expected non-zero (unsurveyed), got exit 0", label))
1928	            }
1929	        }
1930	        Err(e) => rbtdre_Verdict::Fail(format!("{}: {}", label, e)),
1931	    }
1932	}
