1960	//
1961	// Drives zrbld_spine_validate — the Lode capture-assembly spine's dispatch-time
1962	// substitution-coverage check — directly: write a substitution-keys file and an
1963	// already-include-expanded step body, source buv_validation + rblds_Spine and
1964	// kindle buv so buc_log_args resolves, then assert the check accepts a fully
1965	// covered body and returns non-zero at the first _RBGL_* reference absent from
1966	// the keys. The check is sentinel-free and reads only its two file arguments, so
1967	// this stays a dependency-free unit test — no rbld kindle, no regime, no creds.
1968	
1969	fn rbtdrf_rc_run(
1970	    dir: &Path,
1971	    label: &str,
1972	    keys: &str,
1973	    body: &str,
1974	    expect_ok: bool,
1975	) -> rbtdre_Verdict {
1976	    let root = match std::env::current_dir() {
1977	        Ok(r) => r,
1978	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1979	    };
1980	    let keys_file = dir.join(format!("{}-keys.txt", label));
1981	    let body_file = dir.join(format!("{}-body.sh", label));
1982	    if let Err(e) = std::fs::write(&keys_file, keys) {
1983	        return rbtdre_Verdict::Fail(format!("{}: write keys failed: {}", label, e));
1984	    }
1985	    if let Err(e) = std::fs::write(&body_file, body) {
1986	        return rbtdre_Verdict::Fail(format!("{}: write body failed: {}", label, e));
1987	    }
1988	    let buv = root.join(RBTDRF_BUV_VALIDATION);
1989	    let spine = root.join(RBTDRF_RBLDS_SPINE);
1990	    let script = format!(
1991	        "set -euo pipefail\n\
1992	         source '{}'\n\
1993	         source '{}'\n\
1994	         zbuv_kindle\n\
1995	         zrbld_spine_validate '{}' '{}'",
1996	        rbtdrx_native_to_posix(&buv),
1997	        rbtdrx_native_to_posix(&spine),
1998	        rbtdrx_native_to_posix(&keys_file),
1999	        rbtdrx_native_to_posix(&body_file),
2000	    );
2001	
2002	    let expect = if expect_ok { "ok" } else { "non-zero (uncovered)" };
2003	    match rbtdrf_run_bash(&root, &script, dir, label) {
2004	        Ok((code, _, _)) => {
2005	            if (code == 0) == expect_ok {
2006	                rbtdre_Verdict::Pass
2007	            } else {
2008	                rbtdre_Verdict::Fail(format!("{}: expected {}, got exit {}", label, expect, code))
2009	            }
2010	        }
2011	        Err(e) => rbtdre_Verdict::Fail(format!("{}: {}", label, e)),
2012	    }
2013	}
